impl Solution { pub fn minimum_cost(mut nums: Vec<i32>) -> i64 { nums.sort(); let black_m = nums[nums.len() / 2] as i64; let is_p = |mut n: i64| { let (s, mut r) = (n.to_string(), 0i64); s == s.chars().rev().collect::<String>() }; let (mut black_p1, mut black_p2) = (black_m, black_m); while !is_p(black_p1) { black_p1 -= 1; } while !is_p(black_p2) { black_p2 += 1; } [black_p1, black_p2].iter().map(|&p| nums.iter().map(|&x| (x as i64 - p).abs()).sum()).min().unwrap() } }